import{_ as a,o as e,c as s,a5 as d}from"./chunks/framework.QFIuQCaY.js";const g=JSON.parse('{"title":"IMPL-001 — Dirty Checking 기반 HTTP 분기 알고리즘","description":"","frontmatter":{},"headers":[],"relativePath":"decision-log/impl-dirty-fields.md","filePath":"decision-log/impl-dirty-fields.md"}'),i={name:"decision-log/impl-dirty-fields.md"};function n(o,t,l,c,p,r){return e(),s("div",null,[...t[0]||(t[0]=[d(`<h1 id="impl-001-—-dirty-checking-기반-http-분기-알고리즘" tabindex="-1">IMPL-001 — Dirty Checking 기반 HTTP 분기 알고리즘 <a class="header-anchor" href="#impl-001-—-dirty-checking-기반-http-분기-알고리즘" aria-label="Permalink to &quot;IMPL-001 — Dirty Checking 기반 HTTP 분기 알고리즘&quot;">​</a></h1><table tabindex="0"><thead><tr><th>항목</th><th>내용</th></tr></thead><tbody><tr><td>날짜</td><td>2026-03-20</td></tr><tr><td>브랜치</td><td><code>feature/dirty-fields-tracking</code></td></tr><tr><td>상위 결정</td><td><a href="/rest-domain-state-manager/decision-log/ard-0001.html">ARD-0001</a></td></tr><tr><td>상태</td><td>완료</td></tr></tbody></table><h2 id="_1-문제-정의" tabindex="-1">1. 문제 정의 <a class="header-anchor" href="#_1-문제-정의" aria-label="Permalink to &quot;1. 문제 정의&quot;">​</a></h2><h3 id="_1-1-기존-분기-로직의-의미론적-오류" tabindex="-1">1.1 기존 분기 로직의 의미론적 오류 <a class="header-anchor" href="#_1-1-기존-분기-로직의-의미론적-오류" aria-label="Permalink to &quot;1.1 기존 분기 로직의 의미론적 오류&quot;">​</a></h3><p>ARD-0001이 진단한 핵심 결함 중 하나는 <code>save()</code> 의 PUT/PATCH 분기 기준이 잘못되었다는 것이었다. 기존 구현은 다음과 같았다.</p><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 기존 save() 분기 — 의미론적으로 잘못됨</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> log</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> this</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">_getChangeLog</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (log.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">length</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    // PATCH</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">} </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">else</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    // PUT</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><code>changeLog</code> 는 RFC 6902 형식의 감사 이력(Audit Log)이다. <code>changeLog.length === 0</code> 은 &quot;변경 이력이 없다&quot;는 의미이지, &quot;타겟 리소스를 전체 교체해야 한다&quot;는 의미가 아니다. PUT은 RFC 7231 §4.3.4에 따라 타겟 리소스의 <strong>완전한 교체(full replacement)</strong> 를 의미하며, 이 시맨틱을 &quot;변경 이력이 없을 때&quot;와 동일시하는 것은 REST 표준에 어긋난다.</p><p>추가적으로 기존 로직에는 PUT이 필요한 경우인 &quot;70% 이상 필드가 변경된 경우&quot;가 아예 고려되지 않았다.</p><h3 id="_1-2-changelog와-분리된-분기-추적-수단의-필요성" tabindex="-1">1.2 <code>changeLog</code>와 분리된 분기 추적 수단의 필요성 <a class="header-anchor" href="#_1-2-changelog와-분리된-분기-추적-수단의-필요성" aria-label="Permalink to &quot;1.2 \`changeLog\`와 분리된 분기 추적 수단의 필요성&quot;">​</a></h3><p><code>changeLog</code> 를 PUT/PATCH 분기 비율 계산에 직접 사용하는 것도 문제가 있다. 동일 필드를 <code>A → B → A</code> 순으로 두 번 변경하면 <code>changeLog</code> 에는 두 개의 항목이 남지만, 실질적으로 변경된 최상위 키는 0개다. 변경된 필드의 &quot;존재 여부&quot;를 추적하는 데는 <code>Set&lt;string&gt;</code> 이 적합하다.</p><h2 id="_2-설계-결정" tabindex="-1">2. 설계 결정 <a class="header-anchor" href="#_2-설계-결정" aria-label="Permalink to &quot;2. 설계 결정&quot;">​</a></h2><h3 id="_2-1-두-자료구조의-역할-분리" tabindex="-1">2.1 두 자료구조의 역할 분리 <a class="header-anchor" href="#_2-1-두-자료구조의-역할-분리" aria-label="Permalink to &quot;2.1 두 자료구조의 역할 분리&quot;">​</a></h3><table tabindex="0"><thead><tr><th>\\</th><th><code>changeLog</code></th><th><code>_dirtyFields</code></th></tr></thead><tbody><tr><td>자료구조</td><td><code>ChangeLogEntry[]</code> (RFC 6902)</td><td><code>Set&lt;string&gt;</code></td></tr><tr><td>저장 단위</td><td>op 단위 (add/replace/remove)</td><td>최상위 키(top-level key) 단위</td></tr><tr><td>목적</td><td>PATCH 페이로드 직렬화</td><td>PUT/PATCH 분기 비율 계산</td></tr><tr><td>중복 처리</td><td>동일 경로 변경 시 항목이 쌓임</td><td>Set이므로 같은 키는 1회만 기록</td></tr></tbody></table><h3 id="_2-2-최상위-키-top-level-key-추출-원리" tabindex="-1">2.2 최상위 키(Top-level Key) 추출 원리 <a class="header-anchor" href="#_2-2-최상위-키-top-level-key-추출-원리" aria-label="Permalink to &quot;2.2 최상위 키(Top-level Key) 추출 원리&quot;">​</a></h3><p><code>dirtyFields</code> 는 최상위 키만 추적한다. 이것이 <code>totalFields = Object.keys(domainObject).length</code> 와 수학적으로 정합하다.</p><p>경로(path)는 JSON Pointer(RFC 6901) 형식으로 <code>/</code> 로 시작하며, 두 번째 세그먼트가 최상위 키다.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&#39;/name&#39;          → split(&#39;/&#39;)[1] → &#39;name&#39;</span></span>
<span class="line"><span>&#39;/address/city&#39;  → split(&#39;/&#39;)[1] → &#39;address&#39;</span></span>
<span class="line"><span>&#39;/items/0/price&#39; → split(&#39;/&#39;)[1] → &#39;items&#39;</span></span></code></pre></div><p><code>sort</code>, <code>reverse</code> 처럼 배열 전체를 REPLACE로 기록하는 경우에도 <code>basePath</code> 의 두 번째 세그먼트를 추출하므로 정합하다.</p><h3 id="_2-3-dirty-threshold-0-7-선택-근거" tabindex="-1">2.3 DIRTY_THRESHOLD = 0.7 선택 근거 <a class="header-anchor" href="#_2-3-dirty-threshold-0-7-선택-근거" aria-label="Permalink to &quot;2.3 DIRTY_THRESHOLD = 0.7 선택 근거&quot;">​</a></h3><p>PATCH 방식은 변경된 필드만 JSON Patch 배열로 전송하여 페이로드를 줄이는 것이 목적이다. 그러나 변경된 필드 수가 전체의 70% 이상에 달하면 JSON Patch 배열 자체의 직렬화 오버헤드가 전체 객체를 단순 직렬화하는 PUT보다 비효율적이 된다. 0.7은 실무 RESTful API 설계에서 통용되는 경험적 기준값이며, <code>src/constants/dirty.const.js</code> 에 상수로 분리하여 명시적으로 관리한다.</p><p>이 값을 라이브러리 소비자가 재정의하는 공개 옵션은 제공하지 않는다. 경계값 조정 기능을 공개하면 소비자가 이를 잘못 설정할 때 발생하는 버그가 라이브러리 버그인지 설정 오용인지 판단하기 어려워진다. 복잡도 대비 실익이 없다고 판단했다.</p><h3 id="_2-4-최종-분기-알고리즘" tabindex="-1">2.4 최종 분기 알고리즘 <a class="header-anchor" href="#_2-4-최종-분기-알고리즘" aria-label="Permalink to &quot;2.4 최종 분기 알고리즘&quot;">​</a></h3><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>save() 진입</span></span>
<span class="line"><span> │</span></span>
<span class="line"><span> ├─ _isNew === true</span></span>
<span class="line"><span> │    → POST (전체 페이로드 직렬화. isNew 시맨틱: 서버에 아직 없는 신규 리소스)</span></span>
<span class="line"><span> │</span></span>
<span class="line"><span> └─ _isNew === false</span></span>
<span class="line"><span>      │</span></span>
<span class="line"><span>      ├─ dirtyFields.size === 0</span></span>
<span class="line"><span>      │    → PUT (변경 없는 의도적 재저장. 멱등성 보장)</span></span>
<span class="line"><span>      │</span></span>
<span class="line"><span>      ├─ dirtyRatio = dirtyFields.size / Object.keys(target).length</span></span>
<span class="line"><span>      │</span></span>
<span class="line"><span>      ├─ dirtyRatio &gt;= 0.7</span></span>
<span class="line"><span>      │    → PUT (70% 이상 변경 — 전체 교체가 효율적)</span></span>
<span class="line"><span>      │</span></span>
<span class="line"><span>      └─ dirtyRatio &lt; 0.7</span></span>
<span class="line"><span>           → PATCH (RFC 6902 JSON Patch 배열로 변경분만 전송)</span></span></code></pre></div><h3 id="_2-5-edge-case-처리" tabindex="-1">2.5 Edge Case 처리 <a class="header-anchor" href="#_2-5-edge-case-처리" aria-label="Permalink to &quot;2.5 Edge Case 처리&quot;">​</a></h3><p><strong>빈 객체(<code>{}</code>):</strong> <code>totalFields = 0</code> 이면 ZeroDivision을 방지하기 위해 <code>dirtyRatio = 0</code> 으로 강제한다. <code>dirtyFields.size</code> 도 0이므로 PUT으로 분기된다. 빈 도메인 객체에 대한 <code>save()</code> 는 PUT으로 처리하는 것이 의미론적으로 올바르다.</p><p><strong>배열 변이 메서드:</strong> <code>isMuting</code> 플래그로 <code>set</code> 트랩을 차단한 뒤 변이를 실행하고, 완료 후 <code>record()</code> 를 직접 호출하는 방식이므로 <code>_dirtyFields</code> 업데이트가 정상적으로 이루어진다. 별도 처리가 필요 없다.</p><h2 id="_3-변경-파일-및-커밋-시퀀스" tabindex="-1">3. 변경 파일 및 커밋 시퀀스 <a class="header-anchor" href="#_3-변경-파일-및-커밋-시퀀스" aria-label="Permalink to &quot;3. 변경 파일 및 커밋 시퀀스&quot;">​</a></h2><table tabindex="0"><thead><tr><th>파일</th><th>변경 종류</th><th>주요 내용</th></tr></thead><tbody><tr><td><code>src/constants/dirty.const.js</code></td><td>신규</td><td><code>DIRTY_THRESHOLD = 0.7</code> 상수 + JSDoc</td></tr><tr><td><code>src/core/api-proxy.js</code></td><td>수정</td><td><code>dirtyFields: Set</code> 클로저 추가, <code>record()</code> 내 top-level key 추출, <code>ProxyWrapper</code>에 <code>getDirtyFields()</code>, <code>clearDirtyFields()</code> 추가</td></tr><tr><td><code>src/domain/DomainState.js</code></td><td>수정</td><td><code>_getDirtyFields</code>, <code>_clearDirtyFields</code> 바인딩, <code>save()</code> 분기 로직 교체</td></tr><tr><td><code>src/core/api-mapper.js</code></td><td>수정</td><td><code>toPayload()</code> JSDoc에 dirtyFields 기반 분기 시나리오 반영</td></tr></tbody></table><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>feat(constants): add DIRTY_THRESHOLD constant for smart PUT/PATCH routing</span></span>
<span class="line"><span>feat(core): add dirtyFields tracking to createProxy closure</span></span>
<span class="line"><span>feat(domain): replace save() branching with dirtyFields-based smart routing</span></span>
<span class="line"><span>docs(api-mapper): update toPayload() JSDoc to reflect dirty-based PUT routing</span></span></code></pre></div><h2 id="_4-결과-및-검증" tabindex="-1">4. 결과 및 검증 <a class="header-anchor" href="#_4-결과-및-검증" aria-label="Permalink to &quot;4. 결과 및 검증&quot;">​</a></h2><p>분기 알고리즘의 정합성은 다음 5가지 시나리오로 검증했다.</p><table tabindex="0"><thead><tr><th>케이스</th><th>isNew</th><th>dirtyFields</th><th>dirtyRatio</th><th>기대 메서드</th><th>결과</th></tr></thead><tbody><tr><td>신규 리소스</td><td><code>true</code></td><td>—</td><td>—</td><td>POST</td><td>OK</td></tr><tr><td>변경 없는 재저장</td><td><code>false</code></td><td>0개</td><td>0.0</td><td>PUT</td><td>OK</td></tr><tr><td>소량 변경 (5필드 중 1개)</td><td><code>false</code></td><td>1개</td><td>0.2</td><td>PATCH</td><td>OK</td></tr><tr><td>대량 변경 (5필드 중 4개)</td><td><code>false</code></td><td>4개</td><td>0.8</td><td>PUT</td><td>OK</td></tr><tr><td>빈 객체</td><td><code>false</code></td><td>0개</td><td>0.0</td><td>PUT</td><td>OK</td></tr></tbody></table><p>Vitest 테스트 케이스 TC-DS-001~005 통과 확인.</p>`,33)])])}const k=a(i,[["render",n]]);export{g as __pageData,k as default};
